(function () {
    // Отключаем восстановление позиции скролла браузером
    if ('scrollRestoration' in history) {
        history.scrollRestoration = 'manual';
    }
    // Прокручиваем к началу
    window.scrollTo(0, 0);

    const linesContainer = document.querySelector(".lines");
    const hint = document.getElementById("hint");
    const img = document.querySelector('.section1-img');

    const poemLines = [
        "У лукоморья дуб зелёный;",
        "Златая цепь на дубе том:",
        "И днём и ночью кот учёный",
        "Всё ходит по цепи кругом;"
    ];

    let currentIndex = 2;          // следующая пара после первых двух
    let animating = false;
    let shiftsDone = 0;            // сколько раз уже сменили пару строк
    const maxShiftsBeforeFreeScroll = 1; // после одной смены пары даём обычный скролл

    function createLine(text) {
        const div = document.createElement("div");
        div.className = "line-item";
        div.textContent = text;
        return div;
    }

    function init() {
        linesContainer.innerHTML = "";
        linesContainer.appendChild(createLine(poemLines[0]));
        linesContainer.appendChild(createLine(poemLines[1]));
    }

    init();

    function shiftLines() {
        if (animating) return;
        animating = true;

        const oldLines = Array.from(linesContainer.children);

        // Уход старых строк вверх
        oldLines.forEach(el => {
            el.classList.remove("enter", "enter-active");
            el.classList.add("leave");
            // запуск анимации
            requestAnimationFrame(() => {
                el.classList.add("leave-active");
            });
        });

        // Через короткое время убираем старые и добавляем новые
        setTimeout(() => {
            linesContainer.innerHTML = "";

            let added = 0;
            const newLines = [];
            while (currentIndex < poemLines.length && added < 2) {
                const newLine = createLine(poemLines[currentIndex]);
                newLine.classList.add("enter");
                linesContainer.appendChild(newLine);
                newLines.push(newLine);

                currentIndex++;
                added++;
            }

            setTimeout(() => {
                newLines.forEach(el => el.classList.add("enter-active"));
            }, 50);

            if (hint && shiftsDone === 0) {
                hint.classList.add("hidden");
            }

            shiftsDone++;

            img.classList.add('zoomed');

            if (shiftsDone >= maxShiftsBeforeFreeScroll) {
                window.removeEventListener("wheel", handleWheel, { passive: false });
            }

            animating = false;
        }, 350); // быстрый переход, почти без "белого" промежутка
    }

    function handleWheel(e) {
        if (e.deltaY <= 0) return;

        // Блокируем скролл, пока не показали нужные пары строк
        if (shiftsDone < maxShiftsBeforeFreeScroll) {
            e.preventDefault();
            shiftLines();
        }
    }

    window.addEventListener("wheel", handleWheel, { passive: false });
})();

(function () {
    // Отключаем восстановление позиции скролла браузером
    if ('scrollRestoration' in history) {
        history.scrollRestoration = 'manual';
    }
    // Прокручиваем к началу
    window.scrollTo(0, 0);

    const linesContainer = document.querySelector(".lines");
    const hint = document.getElementById("hint");
    const img = document.querySelector('.section1-img');
    const overlay = document.querySelector('.overlay-img');

    const poemLines = [
        "У лукоморья дуб зелёный;",
        "Златая цепь на дубе том:",
        "И днём и ночью кот учёный",
        "Всё ходит по цепи кругом;"
    ];

    let currentIndex = 2;          // следующая пара после первых двух
    let animating = false;
    let shiftsDone = 0;            // сколько раз уже сменили пару строк
    const maxShiftsBeforeFreeScroll = 1; // после одной смены пары даём обычный скролл

    function createLine(text) {
        const div = document.createElement("div");
        div.className = "line-item";
        div.textContent = text;
        return div;
    }

    function init() {
        linesContainer.innerHTML = "";
        linesContainer.appendChild(createLine(poemLines[0]));
        linesContainer.appendChild(createLine(poemLines[1]));
    }

    init();

    function shiftLines() {
        if (animating) return;
        animating = true;

        const oldLines = Array.from(linesContainer.children);

        // Уход старых строк вверх
        oldLines.forEach(el => {
            el.classList.remove("enter", "enter-active");
            el.classList.add("leave");
            // запуск анимации
            requestAnimationFrame(() => {
                el.classList.add("leave-active");
            });
        });

        // Через короткое время убираем старые и добавляем новые
        setTimeout(() => {
            linesContainer.innerHTML = "";

            let added = 0;
            const newLines = [];
            while (currentIndex < poemLines.length && added < 2) {
                const newLine = createLine(poemLines[currentIndex]);
                newLine.classList.add("enter");
                linesContainer.appendChild(newLine);
                newLines.push(newLine);

                currentIndex++;
                added++;
            }

            setTimeout(() => {
                newLines.forEach(el => el.classList.add("enter-active"));
            }, 50);

            if (hint && shiftsDone === 0) {
                hint.classList.add("hidden");
            }

            shiftsDone++;

            img.classList.add('zoomed');
            overlay.classList.add('zoomed');

            if (shiftsDone >= maxShiftsBeforeFreeScroll) {
                window.removeEventListener("wheel", handleWheel, { passive: false });
            }

            animating = false;
        }, 350); // быстрый переход, почти без "белого" промежутка
    }

    function handleWheel(e) {
        if (e.deltaY <= 0) return;

        // Блокируем скролл, пока не показали нужные пары строк
        if (shiftsDone < maxShiftsBeforeFreeScroll) {
            e.preventDefault();
            shiftLines();
        }
    }

    window.addEventListener("wheel", handleWheel, { passive: false });
})();

/* Стили для секций */
.section {
    width: 100%;
    margin: 0;
    padding: 0;
    position: relative;
    overflow: hidden;
}

.section1 {
    /* высота секции = высота изображения */
    display: block;
}

.section1-img {
    display: block;
    width: 100%;
    height: auto;        /* по умолчанию — картинка тянется на всю ширину */
    margin: 0 auto;
}

.intro-inner {
    position: absolute;   /* располагаем текст поверх картинки */
    top: 0;
    right: 0;
    padding: clamp(2rem, 5vw, 4rem) clamp(2rem, 5vw, 4rem) 0 clamp(0.5rem, 1vw, 1rem); /* отступы от правого и верхнего края */
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    color: #000000;
    text-shadow: 0 2px 8px rgba(255, 255, 255, 0.7);
    background: rgba(255, 255, 255, 0.8);
}

.lines-container {
    position: relative;
    width: 45%;
    max-width: 520px;
    min-width: 520px;
    height: calc(
            2 * (clamp(1.8rem, 4vw, 2.6rem) * 1.25) +
            2 * 0.5rem +   /* padding сверху и снизу у каждой строки */
            0.3rem );
    overflow: hidden;
    margin-bottom: 1.5rem;
    background: rgba(255, 255, 255, 0.8);
    padding: 0.5rem;
    border-radius: 0.5rem;
}

.lines {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    transition: transform 0.7s cubic-bezier(0.25, 0.1, 0.25, 1),
    opacity 0.7s ease;
    will-change: transform, opacity;
}

.line-item {
    font-size: clamp(0.65rem, 3.25vw, 1.95rem);
    line-height: 1.25;
    font-weight: 500;
    letter-spacing: 0.02em;
    text-align: center;
    opacity: 1;
    transition: opacity 0.35s ease, transform 0.35s ease;
    padding: 0.2rem 0;
}

.line-item.fading {
    opacity: 0;
}

/* для второй и последующих строк можно добавить лёгкий blur при уходе, если хочется */
.line-item.leaving {
    opacity: 0;
    filter: blur(2px);
}

.line-item.enter {
    opacity: 0;
    transform: translateY(20px);
}

.line-item.enter-active {
    opacity: 1;
    transform: translateY(0);
}

.line-item.leave {
    opacity: 1;
    transform: translateY(0);
}

.line-item.leave-active {
    opacity: 0;
    transform: translateY(-20px);
}
/* На стандартном "широком" окне (примерно 16:9 и шире):
   картинка подгоняется по высоте окна, чтобы целиком влезать,
   а по бокам остаются поля. */
@media (min-aspect-ratio: 16/9) {
    .section1 {
        height: 100vh;
        display: flex;
        justify-content: center;
        align-items: flex-start;
    }

    .section1-img {
        height: 100vh;  /* заполняем высоту окна */
        width: auto;    /* ширина подстраивается, появляются поля слева/справа */
    }
}

.image-wrapper {
    position: relative;
    display: inline-block; /* чтобы wrapper не растягивался на всю ширину */
}

